n ( val ) } "hello"作为string类型存储在interface{}类型的变量val中，[]byte{'a', 'b', 'c'}作为slice存储在interface{}类型的变量val中。这个过程是隐式的，是编译期确定的 接口的具体实现 package main import ( fmt ) // 演讲者接口 type Speaker interface { // 说 Say ( string ) // 听 Listen ( string ) string // 打断、插嘴 Interrupt ( string ) } // 王兰讲师 type WangLan struct { msg string } func ( this * WangLan ) Say ( msg string ) { fmt . Printf ( 王兰说：%s
 , msg ) } func ( this * WangLan ) Listen ( msg string ) string { this . msg = msg return msg } func ( this * WangLan ) Interrupt ( msg string ) { this . Say ( msg ) } // 江娄讲师 type JiangLou struct { msg string } func ( this * JiangLou ) Say ( msg string ) { fmt . Printf ( 江娄说：%s
 , msg ) } func ( this * JiangLou ) Listen ( msg string ) string { this . msg = msg return msg } func ( this * JiangLou ) Interrupt ( msg string ) { this . Say ( msg ) } func main () { wl := WangLan {} jl := JiangLou {} //person是Speaker的具体实现,可以理解为person是Speaker类型的变量 //var i int i = 2 var person Speaker person = wl person . Say ( Hello World! ) person = jl person . Say ( Good Luck! ) } 三种断言方式: 带ok的类型断言 if value , ok := element .( string ); ok { fmt . Printf ( html[%d] is a string and its value is %s
 , index , value ) } else if value , ok := element .([] byte ); ok { fmt . Printf ( html[%d] is a []byte and its value is %s
 , index , string ( value )) } 不带ok的类型断言 value := element .( T ) switch switch value := element .( type ) { case string : fmt . Printf ( html[%d] is a string and its value is %s
 , index , value ) case [] byte : fmt . Printf ( html[%d] is a []byte and its value is %s
 , index , string ( value )) case int : fmt . Printf ( invalid type
 ) default : fmt . Printf ( unknown type
 ) }

